mapper.select:
SELECT id, source, category, title, summary, url, corp_name, content_hash, to_char(published_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI') AS published_at, to_char(created_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI') AS created_at FROM hub_news WHERE 1 = 1
AND source = #{cond.source}
AND ( title ILIKE '%' || #{cond.keyword} || '%' OR corp_name ILIKE '%' || #{cond.keyword} || '%' )
ORDER BY published_at DESC LIMIT #{cond.size} OFFSET #{cond.offset}

SELECT COUNT(*) FROM hub_news WHERE 1 = 1
AND source = #{cond.source}
AND ( title ILIKE '%' || #{cond.keyword} || '%' OR corp_name ILIKE '%' || #{cond.keyword} || '%' )
